#[derive(Error, Debug)]
pub enum Error {
    #[error("from rustls")]
    Rustls(#[from] rustls::Error),
    #[error("I/O error")]
    Io(#[from] std::io::Error),
    #[error("JSON error")]
    Json(#[from] serde_json::Error),
    #[error("keygen error")]
    Keygen(#[from] crate::crypto::KeygenError),
}

mod endpoint;

#[repr(transparent)]
#[derive(
    Clone,
    Copy,
    Debug,
    PartialEq,
    Eq,
    Hash,
    PartialOrd,
    Ord,
    derive_more::Deref,
    derive_more::From,
    derive_more::Into,
    derive_more::AsRef,
    derive_more::Display,
    derive_more::FromStr,
    Serialize,
    Deserialize,
)]
#[display("{_0}")]
#[serde(transparent)]
pub struct PeerId(Hash32);
forward_try_from_slice!(PeerId, Hash32);

impl PeerId {
    /// Compute a `PeerId` as SHA256(SHA256(SPKI_DER)).
    pub fn from_spki_der(spki_der: &[u8]) -> Self {
        PeerId(crypto::sha256d(spki_der))
    }
}

#[derive(Clone, Debug, PartialEq, Eq, Deserialize, Serialize)]
pub struct UnverifiedPeer {
    #[serde(rename = "id")]
    pub(crate) peer_id: PeerId,
    #[serde(rename = "entrypoints", default = "Vec::new")]
    pub endpoints: Vec<PeerEndpoint>,
}

impl From<PublicPeer> for UnverifiedPeer {
    fn from(other: PublicPeer) -> Self {
        Self {
            peer_id: other.peer_id,
            endpoints: other.endpoints,
        }
    }
}

impl From<PrivatePeer> for UnverifiedPeer {
    fn from(other: PrivatePeer) -> Self {
        Self {
            peer_id: other.peer_id,
            endpoints: other.endpoints,
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq, Deserialize, Serialize)]
pub struct PublicPeer {
    #[serde(rename = "id")]
    pub(crate) peer_id: PeerId,
    #[serde(rename = "pubKey")]
    pub(crate) pub_key: crypto::PublicKey,
    #[serde(
        rename = "entrypoints",
        skip_serializing_if = "Vec::is_empty",
        default = "Vec::new"
    )]
    pub endpoints: Vec<PeerEndpoint>,
}

impl From<PrivatePeer> for PublicPeer {
    fn from(other: PrivatePeer) -> Self {
        Self {
            peer_id: other.peer_id,
            pub_key: other.pub_key,
            endpoints: other.endpoints,
        }
    }
}

#[derive(Clone, Debug, PartialEq, Eq, Deserialize, Serialize)]
pub struct PrivatePeer {
    #[serde(rename = "id")]
    pub(crate) peer_id: PeerId,
    #[serde(rename = "pubKey")]
    pub(crate) pub_key: crypto::PublicKey,
    #[serde(rename = "privKey")]
    pub(crate) priv_key: crypto::PrivateKey,
    #[serde(
        rename = "entrypoints",
        skip_serializing_if = "Vec::is_empty",
        default = "Vec::new"
    )]
    pub endpoints: Vec<PeerEndpoint>,
}

impl PrivatePeer {
    pub fn generate(params: crate::crypto::KeygenParams) -> Result<Self, Error> {
        use crate::crypto::gen_keypair;
        let (priv_key, pub_key) = gen_keypair(params)?;
        let peer_id = pub_key.gen_peer_id();
        let endpoints = vec![];
        Ok(Self {
            peer_id,
            pub_key,
            priv_key,
            endpoints,
        })
    }

    pub fn generate_default() -> Result<Self, Error> {
        #[cfg(feature = "crypto-graviola")]
        {
            use crate::crypto::{EcdsaKeygenParams, KeygenParams};
            Self::generate(KeygenParams::Ecdsa(EcdsaKeygenParams::EcdsaP256Sha256))
        }
        #[cfg(not(feature = "crypto-graviola"))]
        {
            Self::generate(Default::default())
        }
    }

    pub fn load_file<P: AsRef<Path>>(path: P) -> Result<PrivatePeer, Error> {
        use std::fs::File;
        use std::io::BufReader;
        let reader = BufReader::new(File::open(path)?);
        Ok(serde_json::from_reader(reader)?)
    }

    pub fn get_private_key(&self) -> PrivateKeyDer<'static> {
        self.priv_key.for_rustls()
    }

    pub fn get_public_key_der(&self) -> crate::crypto::PublicKey {
        self.pub_key.clone()
    }

    pub fn gen_certificate(&self) -> CertificateDer<'static> {
        use crate::ca::CertificateBuilder;
        CertificateBuilder::new(self.get_public_key_der()).build()
    }

    pub fn gen_client_config(&self) -> Result<Arc<ClientConfig>, Error> {
        use crate::crypto::NoSanVerification;
        use rustls::version::TLS13;
        let peer_cert = self.gen_certificate();
        let private_key = self.get_private_key();
        let root_store = crate::ca::ROOT_STORE.clone();
        let config = ClientConfig::builder_with_protocol_versions(&[&TLS13])
            .dangerous()
            .with_custom_certificate_verifier(Arc::new(NoSanVerification::new(root_store.clone())))
            .with_client_auth_cert(vec![peer_cert], private_key.clone_key())?;
        Ok(Arc::new(config))
    }

    pub fn gen_server_config(&self) -> Result<Arc<ServerConfig>, Error> {
        use rustls::server::WebPkiClientVerifier;
        use rustls::version::TLS13;
        let peer_cert = self.gen_certificate();
        let private_key = self.get_private_key();
        // Require client authentication against our embedded CA
        let client_verifier = WebPkiClientVerifier::builder(crate::ca::ROOT_STORE.clone())
            .build()
            .expect("client verifier");
        let config = ServerConfig::builder_with_protocol_versions(&[&TLS13])
            .with_client_cert_verifier(client_verifier)
            .with_single_cert(vec![peer_cert], private_key.clone_key())?;
        Ok(Arc::new(config))
    }
}

